section.code:
{
  "__faion_header__": {
    "methodology": "surveys",
    "version": "1.1.0",
    "produces": "config"
  },
  "research_question": "Did the new onboarding flow improve first-week feature adoption and task ease?",
  "instrument": [
    "nps",
    "seq"
  ],
  "items": [
    {
      "id": "q1",
      "text": "How likely are you to recommend this product to a colleague?",
      "scale": "nps-0-10",
      "labels": [
        "0=not at all",
        "10=extremely"
      ]
    },
    {
      "id": "q2",
      "text": "How easy was completing the onboarding tutorial?",
      "scale": "likert-1-5",
      "labels": [
        "1=very difficult",
        "2=difficult",
        "3=neither",
        "4=easy",
        "5=very easy"
      ]
    }
  ],
  "sampling": {
    "target_n": 400,
    "channels": [
      "in-app",
      "email"
    ],
    "fielding_window_days": 14,
    "response_rate_target_pct": 25
  },
  "analysis_plan": {
    "cross_tabs": [
      "plan_tier",
      "tenure_days"
    ],
    "weighting": "tenure-balanced",
    "significance_test": "t-test"
  }
}
